#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long p;
        scanf("%lld", &p);
        long long ans = 0;
        for (long long a = p + 1; a <= 2 * p; a++) {
            for (long long b = a; b <= 2 * p; b++) {
                if ((a - p) * (b - p) != 0 && (a * b) % ((a - p) * (b - p)) == 0) {
                    ans++;
                }
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

